        c.execute("SELECT user_id FROM leads WHERE status=?", (status_filter,))
    else:
        c.execute("SELECT user_id FROM leads")

    users = c.fetchall()
    conn.close()

    for (user_id,) in users:
        line_push(user_id, message)

    return {"sent": len(users)}



