import { useEffect, useState } from "react";
import {
  DragDropContext, Droppable, Draggable
} from "react-beautiful-dnd";

const columns = ["cold", "warm", "hot", "closed"];

export default function App() {
  const [token, setToken] = useState(localStorage.getItem("token"));
  const [leads, setLeads] = useState([]);

  async function login() {
    const res = await fetch("http://localhost:8000/login", {
      method: "POST",
      headers: {"Content-Type": "application/json"},
      body: JSON.stringify({ username: "admin", password: "1234" })
    });
    const data = await res.json();
    localStorage.setItem("token", data.token);
    setToken(data.token);
  }

  async function loadLeads() {
    const res = await fetch("http://localhost:8000/api/leads", {
      headers: { Authorization: `Bearer ${token}` }
    });
    setLeads(await res.json());
  }

  useEffect(() => {
    if (token) loadLeads();
  }, [token]);

  async function updateStatus(id, status) {
    await fetch(`http://localhost:8000/api/leads/${id}`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`
      },
      body: JSON.stringify({ status })
    });
    loadLeads();
  }

  function onDragEnd(result) {
    if (!result.destination) return;
    const id = parseInt(result.draggableId);
    const newStatus = result.destination.droppableId;
    updateStatus(id, newStatus);
  }

  async function broadcast() {
    const msg = prompt("Message?");
    await fetch("http://localhost:8000/api/broadcast", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`
      },
      body: JSON.stringify({ message: msg })
    });
  }

  if (!token) return <button onClick={login}>Login</button>;

  return (
    <div style={{ padding: 20 }}>
      <h1>Kanban CRM</h1>

      <button onClick={broadcast}>Broadcast</button>

      <DragDropContext onDragEnd={onDragEnd}>
        <div style={{ display: "flex", gap: 20 }}>
          {columns.map(col => (
            <Droppable droppableId={col} key={col}>
              {(provided) => (
                <div
                  ref={provided.innerRef}
                  {...provided.droppableProps}
                  style={{
                    width: 250,
                    minHeight: 400,
                    border: "1px solid #ccc",
                    padding: 10
                  }}
                >
                  <h3>{col}</h3>

                  {leads
                    .filter(l => l.status === col)
                    .map((l, i) => (
                      <Draggable
                        key={l.id}
                        draggableId={String(l.id)}
                        index={i}
                      >
                        {(p) => (
                          <div
                            ref={p.innerRef}
                            {...p.draggableProps}
                            {...p.dragHandleProps}
                            style={{
                              padding: 10,
                              margin: "10px 0",
                              background: "#eee",
                              ...p.draggableProps.style
                            }}
                          >
                            <b>{l.name}</b>
                            <div>{l.phone}</div>
                            <small>{l.interest}</small>
                          </div>
                        )}
                      </Draggable>
                    ))}

                  {provided.placeholder}
                </div>
              )}
            </Droppable>
          ))}
        </div>
      </DragDropContext>
    </div>
  );
}



