def check_quota(db, tenant_id):
    today = datetime.now().date().isoformat()

    u = db.query(Usage).filter(
        Usage.tenant_id == tenant_id,
        Usage.date == today
    ).first()

    t = db.query(Tenant).get(tenant_id)

    if not u:
        return True

    limits = PLAN_LIMITS.get(t.plan, PLAN_LIMITS["free"])

    if u.messages >= limits["messages"]:
        return False

    if u.leads >= limits["leads"]:
        return False

    return True



